document.querySelectorAll('a[href^="/#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();const n=this.getAttribute("href").substring(2),t=document.getElementById(n);t&&(t.scrollIntoView({behavior:"smooth",block:"start"}),document.getElementById("mainNav").classList.remove("active"),document.getElementById("mobileMenuBtn").classList.remove("active"))})}),document.getElementById("mobileMenuBtn").addEventListener("click",function(){this.classList.toggle("active"),document.getElementById("mainNav").classList.toggle("active")});const header=document.getElementById("header");window.addEventListener("scroll",()=>{window.pageYOffset>60?header.classList.add("scrolled"):header.classList.remove("scrolled")},{passive:!0});const observer=new IntersectionObserver(e=>{e.forEach(e=>{e.isIntersecting&&e.target.classList.add("visible")})},{threshold:.1});document.querySelectorAll(".reveal").forEach(e=>observer.observe(e))